export type POICategory =
  | 'Culture'
  | 'Nature'
  | 'Food & Drink'
  | 'Entertainment'
  | 'Shopping'
  | 'History'
  | 'Nightlife'
  | 'Relaxation'
  | 'Family-Friendly'
  | 'Hidden Gems';

export interface POI {
  id: string;
  name: string;
  lat: number;
  lng: number;
  category: POICategory;
  isFree: boolean;
  price: number;
  hasISIC: boolean;
  dTicket: boolean;
  estimatedSteps: number;
}

export function getVisitMinutes(poi: POI): number {
  switch (poi.category) {
    case 'Culture':
    case 'History':
      if (!poi.isFree && poi.price >= 15) return 120;
      if (!poi.isFree) return 90;
      return poi.estimatedSteps > 2000 ? 60 : 30;
    case 'Nature':
      if (poi.estimatedSteps >= 7000) return 120;
      if (poi.estimatedSteps >= 4000) return 60;
      return 45;
    case 'Food & Drink':
      return poi.price > 15 ? 90 : 45;
    case 'Nightlife':
      return 180;
    case 'Entertainment':
      return 120;
    case 'Shopping':
      return 90;
    case 'Relaxation':
      return 150;
    case 'Family-Friendly':
      return 120;
    case 'Hidden Gems':
      return 45;
    default:
      return 60;
  }
}

export interface City {
  id: string;
  name: string;
  center: [number, number];
  zoom: number;
  airportIATA: string;
  pois: POI[];
}

